mapper.select:
SELECT user_id, username, email, nickname, role, email_verified_at, created_at, deleted_at, account_status FROM users
account_status = #{accountStatus}
AND nickname LIKE CONCAT('%', #{keyword}, '%')
AND username LIKE CONCAT('%', #{keyword}, '%')
ORDER BY user_id DESC LIMIT #{size} OFFSET #{offset}

SELECT username, email, nickname, profile_image_url, bio, role, account_status, email_verified_at
FROM users
WHERE username = #{username}

SELECT user_id, username, email, password, role, account_status, email_verified_at
FROM users
WHERE username = #{username}

SELECT COUNT(*)
FROM users
WHERE email = #{email}

mapper.update:
UPDATE user_suspensions
SET released_at = CURRENT_TIMESTAMP,
	released_by = #{releasedBy},
	release_reason = #{releaseReason}
WHERE active_user_id = #{userId}

mapper.select:
SELECT reason, suspended_until
FROM user_suspensions
WHERE active_user_id = #{userId}

mapper.update:
UPDATE users
SET role = #{role}
WHERE user_id = #{userId}
  AND account_status != 'DELETED'
